$repos = @("designflow-backend", "designflow-bff", "designflow-data-syncing", "designflow-frontend", "designflow-item-master", "designflow-tracking")
$base = "C:\repos\dflow plm"
foreach ($repo in $repos) {
    $path = Join-Path $base $repo
    if (Test-Path $path) {
        Write-Host "=== $repo ===" -ForegroundColor Cyan
        git -C $path fetch origin 2>&1
        git -C $path status --short --branch 2>&1
    } else {
        Write-Host "=== $repo === NOT FOUND" -ForegroundColor Red
    }
}

$repos = @("designflow-backend", "designflow-bff", "designflow-data-syncing", "designflow-frontend", "designflow-item-master", "designflow-tracking")
$base = "C:\repos\dflow plm"
foreach ($repo in $repos) {
    $path = Join-Path $base $repo
    $result = git -C $path log --diff-filter=D --name-only --oneline --since="90 days ago" -- "*aws*" "*sdk*" 2>&1
    if ($result) {
        Write-Host "=== $repo ===" -ForegroundColor Cyan
        Write-Host $result
        Write-Host ""
    }
}

$repos = @("designflow-backend", "designflow-bff", "designflow-data-syncing", "designflow-frontend", "designflow-item-master", "designflow-tracking")
$base = "C:\repos\dflow plm"
foreach ($repo in $repos) {
    $path = Join-Path $base $repo
    # Search for any commit message mentioning aws or sdk
    $result = git -C $path log --oneline --since="90 days ago" --all --grep="aws" -i 2>&1
    if ($result) {
        Write-Host "=== $repo (commits mentioning aws) ===" -ForegroundColor Cyan
        Write-Host $result
    }
    # Also check for deleted files with aws in the path, no time limit
    $result2 = git -C $path log --diff-filter=D --name-only --oneline -- "*aws*" 2>&1
    if ($result2) {
        Write-Host "=== $repo (deleted aws files, all time) ===" -ForegroundColor Yellow
        Write-Host $result2
    }
}
